INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('总能企投 HR-HRBP 实习生 - 北京（实习）', '互联网 / IT', '北京', '民营企业', 150, 200, '熟练操作 Office 办公软件', '具备较强的思考与总结能力，工作热情主动；责任心强，抗压能力突出', 1, '极度友好', '1. 支持招聘与培训工作：助力 HRBP 团队推进校园招聘、培训等项目，涵盖需求调研、项目运营等环节； 2. 协助活动项目筹备：参与培训及员工关系相关活动的策划、执行与宣传推广； 3. 支持其他 HR 模块：为文化建设、组织发展等工作提供辅助。', '招聘全流程执行, 校招项目运营, OD 组织发展支持, 员工关系支持', '本科及以上', '人力资源、管理学等相关专业优先', '27 届本科或研究生在读生，每周至少出勤 4-5 天，实习期≥3 个月', '日常实习', '有 HRBP 相关实习经验者优先', '150-200 元 / 天', '46097', '46386', 'https://www.shixiseng.com/intern/inn_u5hjwvygllwu?pcm=pc_SearchList&_refluxos=a10', '招聘类 (含招聘专员 / 助理 / 校招专员)', '甲方（企业自有 HR 岗）'), ('招聘经理（带团队） - 岳阳（社招）', '互联网 / IT', '岳阳', '民营企业', 6000, 8000, '1. 熟悉招聘及培训流程，具备丰富的个人招聘经验及招聘团队管理经验和技巧； 2. 熟悉办公软件，具备良好的网络知识； 3. 能清晰勾勒出各岗位素质模型，人才画像，实现组织的人岗匹配。', '1. 认可公司及企业文化，认同行业，对职业规划有清晰的追求； 2. 性格开朗，乐于助人，正直，忠诚守信，擅于沟通与协调，团队合作意识较强； 3. 有业务协同经验或业务管理、业务培训等经验，足够认可公司平台及产品。', 0, '一般', '1. 参与制定人力资源战略规划，负责公司的组织架构完整和人才储备负责； 2. 带领团队保质保量完成公司每月制定的招聘任务及指标； 3. 协助人力资源总监制定相应的岗位说明书，并根据公司职位调整需要进行相应的变更，描绘岗位画像及美人形成人员匹配； 4. 组织策划黄埔军校培训事宜，落地的具体流程，标准，确保新人快速融入； 5. 每月针对组织架构及人员结构进行人员盘点，直缺补漏出分析报告，制定招聘计划、人才画像、岗位分析、招聘指标分解及工作计划，进行初步的面试与筛选，做好各部门间的协调工作等。', '候选人寻访 /mapping, 招聘全流程执行, 招聘数据分析, OD 组织发展支持, 校招项目运营', '大专及以上', '人力资源管理、工商管理、劳动与社会保障等相关专业', '1-3 年工作经验，具备招聘团队管理经验优先', '社招（应届生可投）', '有人力资源管理师相关证书； 有大型企业 / 互联网行业 HR 管理经验。', '6000-8000 元 / 月 13 薪', '45658', NULL, 'BOSS直聘获取', '招聘类 (含招聘专员 / 助理 / 校招专员)', '甲方（企业自有 HR 岗）'), ('bpo 行业招聘经理 - 滁州（社招）', '人力资源服务 / 咨询', '滁州', '民营企业', 9000, 12000, '1. 熟悉各类招聘渠道及面试方法，具备中高端岗位招聘经验； 2. 熟练使用办公软件，具备招聘数据统计与分析能力； 3. 具备招聘体系搭建与流程优化能力。', '1. 具备优秀的沟通协调能力与团队管理能力； 2. 目标感强，具备较强的执行力与抗压能力； 3. 具备良好的跨部门协作能力。', 0, '一般', '1. 制定并执行公司整体招聘计划，满足各部门用人需求； 2. 搭建、优化招聘体系与流程，完善岗位说明书、面试题库等； 3. 拓展并维护招聘渠道（招聘网站、猎头、校园、内推等）； 4. 主导中高端岗位寻访、面试、评估与录用跟进，把控招聘质量； 5. 分析招聘数据，优化招聘效率，控制招聘成本； 6. 对接业务部门，明确用人标准，提升人岗匹配度； 7. 管理招聘团队，指导招聘专员开展工作。', '招聘全流程执行, 渠道拓展与运营, 候选人寻访 /mapping, 简历筛选与面试, 招聘数据分析', '大专及以上', '人力资源管理、工商管理等相关专业优先', '1-3 年工作经验，5 年及以上招聘工作经验，2 年以上招聘管理经验', '社招（应届生可投）', '1. 有人力资源管理师相关证书； 2. 有 BPO 行业招聘管理经验。', '9000-12000 元 / 月 13薪', '46112', NULL, 'BOSS直聘获取', '招聘类 (含招聘专员 / 助理 / 校招专员)', '甲方（企业自有 HR 岗）'), ('招聘经理 - 崇左（社招）', '其他', '崇左', '民营企业', 6000, 7000, '1. 熟悉招聘全流程，能灵活运用各类招聘工具和方法； 2. 具备基础的招聘计划制定与流程管理能力； 3. 熟练使用办公软件。', '1. 具备优秀的沟通表达能力与团队合作精神； 2. 具备较强的组织能力与计划能力； 3. 具备良好的问题解决能力，工作积极热情', 1, '友好', '1. 负责组织和实施招聘流程，包括但不限于职位发布、筛选简历、组织面试； 2. 制定招聘策略，优化招聘渠道，提高招聘效率； 3. 与团队合作，确保招聘计划的实施符合公司发展需求； 4. 管理招聘团队，提升团队成员的专业能力和服务水平； 5. 保持沟通，确保招聘流程的透明和高效。', '招聘全流程执行, 招聘数据分析, 简历筛选与面试, 渠道拓展与运营', '大专及以上', '人力资源管理、工商管理等相关专业优先      ', '经验不限，有无经验均可，公司提供新人培训班', '社招（应届生可投）', '1. 有汽车、房地产、猎头行业招聘经验； 2. 有团队搭建与管理经验。', '6000-7000 元 / 月        ', '46112', NULL, 'BOSS直聘获取', '招聘类 (含招聘专员 / 助理 / 校招专员)', '甲方（企业自有 HR 岗）'), ('招聘经理（居家可兼职） - 重庆（社招）', '人力资源服务 / 咨询', '重庆', '民营企业', 12000, 24000, '1. 能独立使用招聘软件，能深刻理解岗位 JD； 2. 具备基础的候选人寻访、沟通与跟进能力； 3. 熟练使用微信、电话等沟通工具。', '1. 对人力资源行业有热情，踏实肯干，有活力； 2. 亲和力强，具备优秀的沟通表达能力与情商； 3. 执行力强，目标感强，有赚钱欲望与抗压能力。', 1, '友好', '1. 在老师的指导下，使用招聘平台，实施招聘工作； 2. 寻访合适的候选人，完成电话沟通、微信推送及面试跟进； 3. 跟进并解答候选人在过程中遇到的问题，保证招聘流程顺利； 4. 对接甲方跟踪项目进度，协助候选人完成入职流程； 5. 完成 Team leader 分配的其他工作任务。', '招聘全流程执行, 候选人寻访 /mapping, 简历筛选与面试', '大专及以上', '人力资源管理、工商管理等相关专业优先', '3-5 年工作经验，有甲方 / 乙方招聘专员、人事相关经验优先，无经验可免费培训', '社招（应届生可投）', '1. 有甲方 / 乙方招聘相关经验； 2. 有猎头、RPO 行业经验。', '12000-24000 元 / 月', '46112', NULL, 'B0SS直聘获取', '招聘类 (含招聘专员 / 助理 / 校招专员)', '乙方（人力资源服务商 / 猎头 / 咨询公司）');